prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?model
  ?modelName
  ?normId
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?seqFlow) AS ?seqFlowCount)
  (COUNT(DISTINCT ?msgFlow) AS ?msgFlowCount)
  (COUNT(DISTINCT ?gw) AS ?gatewayCount)
WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:normalizedId ?normId ;
         tai:belongsTo ?org .
  FILTER(STR(?normId) = "4ccc3fd711004f519782ac92e58f6ddd")

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
  OPTIONAL { ?seqFlow a bbo:SequenceFlow ; tai:belongsTo ?choreo . }
  OPTIONAL { ?msgFlow a bboExt:MessageFlow ; tai:belongsTo ?choreo . }
  OPTIONAL { ?gw a ?gwType ; tai:belongsTo ?choreo .
             FILTER(?gwType IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
           }
}
GROUP BY ?model ?modelName ?normId
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?model
  ?modelName
  ?normId
  ?origId
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?seqFlow) AS ?seqFlowCount)
  (COUNT(DISTINCT ?msgFlow) AS ?msgFlowCount)
  (COUNT(DISTINCT ?gw) AS ?gatewayCount)
WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:belongsTo ?org .

  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }

  FILTER(
    (BOUND(?normId) && STR(?normId) = "4ccc3fd711004f519782ac92e58f6ddd") ||
    (BOUND(?origId) && STR(?origId) = "4ccc3fd711004f519782ac92e58f6ddd") ||
    (BOUND(?normId) && CONTAINS(LCASE(STR(?normId)), LCASE("4ccc3fd711004f519782ac92e58f6ddd"))) ||
    (BOUND(?origId) && CONTAINS(LCASE(STR(?origId)), LCASE("4ccc3fd711004f519782ac92e58f6ddd")))
  )

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
  OPTIONAL { ?seqFlow a bbo:SequenceFlow ; tai:belongsTo ?choreo . }
  OPTIONAL { ?msgFlow a bboExt:MessageFlow ; tai:belongsTo ?choreo . }
  OPTIONAL {
    ?gw a ?gwType ; tai:belongsTo ?choreo .
    FILTER(?gwType IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
  }
}
GROUP BY ?model ?modelName ?normId ?origId
ORDER BY DESC(?taskCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?model
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?start) AS ?startCount)
  (COUNT(DISTINCT ?catch) AS ?catchCount)
  (COUNT(DISTINCT ?end) AS ?endCount)
  (COUNT(DISTINCT ?seqFlow) AS ?seqFlowCount)
  (COUNT(DISTINCT ?msgFlow) AS ?msgFlowCount)
  (COUNT(DISTINCT ?xor) AS ?xorCount)
  (COUNT(DISTINCT ?and) AS ?andCount)
  (COUNT(DISTINCT ?eventGw) AS ?eventGwCount)
WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org .
  ?model tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
  OPTIONAL { ?start a bboExt:StartEvent ; tai:belongsTo ?choreo . }
  OPTIONAL { ?catch a bboExt:IntermediateCatchEvent ; tai:belongsTo ?choreo . }
  OPTIONAL { ?end a bboExt:EndEvent ; tai:belongsTo ?choreo . }
  OPTIONAL { ?seqFlow a bbo:SequenceFlow ; tai:belongsTo ?choreo . }
  OPTIONAL { ?msgFlow a bboExt:MessageFlow ; tai:belongsTo ?choreo . }

  OPTIONAL { ?xor a bboExt:ExclusiveGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?and a bboExt:ParallelGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?eventGw a bboExt:EventBasedGateway ; tai:belongsTo ?choreo . }
}
GROUP BY ?model
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?elem
  ?name
  ?type
  WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  {
    ?task a bboExt:ChoreographyTask .
    FILTER EXISTS { ?task bbo:name ?n1 }
    OPTIONAL { ?task bbo:name ?name }
    BIND(?task as ?elem)
    BIND(bboExt:ChoreographyTask as ?type)
  }
  UNION
  {
    ?gw a bboExt:ExclusiveGateway .
    OPTIONAL { ?gw bbo:name ?name }
    BIND(?gw as ?elem)
    BIND(bboExt:ExclusiveGateway as ?type)
  }
  UNION
  {
    ?start a bboExt:StartEvent .
    OPTIONAL { ?start bbo:name ?name }
    BIND(?start as ?elem)
    BIND(bboExt:StartEvent as ?type)
  }
  UNION
  {
    ?end a bboExt:EndEvent .
    OPTIONAL { ?end bbo:name ?name }
    BIND(?end as ?elem)
    BIND(bboExt:EndEvent as ?type)
  }
}
ORDER BY ?type ?name
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?choreoName
  ?task
  ?taskName
  ?initPartName
  (SAMPLE(?loopType) as ?loopType)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  OPTIONAL { ?choreo bbo:name ?choreoName . }

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task bboExt:loopType ?loopType . }
  OPTIONAL {
    ?task bboExt:initiatingParticipantRef ?partRef .
    ?part a bboExt:Participant ; tai:belongsTo ?choreo ; bbo:name ?initPartName .
    FILTER(STRENDS(STR(?part), ?partRef) || CONTAINS(LCASE(STR(?part)), LCASE(?partRef)))
  }
}
GROUP BY ?choreoName ?task ?taskName ?initPartName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?msg
  ?sourceRef
  ?targetRef
  ?sourceName
  ?targetName
  ?choreo
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  ?msg a bboExt:MessageFlow ; tai:belongsTo ?choreo ;
       bboExt:sourceRef ?sourceRef ;
       bboExt:targetRef ?targetRef .

  OPTIONAL {
    ?sPart a bboExt:Participant ; tai:belongsTo ?choreo ; bbo:name ?sourceName .
    FILTER(STRENDS(STR(?sPart), ?sourceRef))
  }
  OPTIONAL {
    ?tPart a bboExt:Participant ; tai:belongsTo ?choreo ; bbo:name ?targetName .
    FILTER(STRENDS(STR(?tPart), ?targetRef))
  }
}
LIMIT 25
